from causallearn.graph.GraphNode import GraphNode
from causallearn.search.ScoreBased.GES import ges; from causallearn.utils.cit import CIT
def run_causal_discovery(X: np.ndarray) -> GeneralGraph:
    n_samples, n_vars = X.shape
    if n_vars <= 12:
        from causallearn.search.PermutationBased.BOSS import boss; return boss(X, score_func="local_score_BDeu", parameters={"equivalent_sample_size": 10})
    G = ges(X, score_func="local_score_BDeu", parameters={"equivalent_sample_size": 10})['G']
    nmap = {n.get_name(): int(n.get_name()[1:]) - 1 for n in G.get_nodes()}; cit_test = CIT(X, "chisq")
    for e in list(G.get_graph_edges()):
        i, j = nmap[e.get_node1().get_name()], nmap[e.get_node2().get_name()]; S = [nmap[n.get_name()] for n in G.get_adjacent_nodes(e.get_node1()) if n != e.get_node2()][:3]
        if cit_test(i, j, S) > 0.05: G.remove_edge(e)
    return G

from causallearn.search.ScoreBased.GES import ges; from causallearn.utils.cit import CIT
def run_causal_discovery(X: np.ndarray) -> GeneralGraph:
    n, p = X.shape; G = ges(X, score_func="local_score_BDeu")['G']
    cit = CIT(X, "gsq"); nds = G.get_nodes(); nm = {nds[k]: k for k in range(len(nds))}
    cards = [len(np.unique(X[:, k])) for k in range(p)]
    for edge in list(G.get_graph_edges()):
        i, j = nm[edge.get_node1()], nm[edge.get_node2()]
        nbrs = sorted((set(nm[nb] for nb in G.get_adjacent_nodes(edge.get_node1())) | set(nm[nb] for nb in G.get_adjacent_nodes(edge.get_node2()))) - {i, j})
        tests = [[]] + [[k] for k in nbrs] + ([nbrs] if len(nbrs) > 1 else [])
        ok = [t for t in tests if cards[i]*cards[j]*int(np.prod([cards[k] for k in t]+[1])) <= n//5]
        if any(cit(i, j, t) > 0.01 for t in ok): G.remove_edge(edge)
    return G
